const result = $json.agent_result || $json.result || $json;
const criteria = Array.isArray($json.criteria) ? $json.criteria : [];
const evidence = Array.isArray(result.evidence) ? result.evidence : [];
const checks = criteria.map((criterion) => {
  const item = evidence.find((entry) => entry.criterion === criterion);
  return {
    criterion,
    status: item?.status || 'unknown',
    evidence: item?.detail || 'No evidence provided.'
  };
});
const scoreMap = { pass: 1, unknown: 0.5, fail: 0 };
const score = checks.length === 0
  ? 0
  : checks.reduce((sum, item) => sum + scoreMap[item.status], 0) / checks.length;
const criteriaMet = checks.length > 0 && checks.every((item) => item.status === 'pass');
const failedCriteria = checks.filter((item) => item.status !== 'pass');

return [{
  json: {
    criteria_met: criteriaMet,
    score: Number(score.toFixed(2)),
    checks,
    next_iteration_instruction: criteriaMet
      ? null
      : failedCriteria.map((item) => `Improve criterion: ${item.criterion}`).join('; '),
    should_stop: false,
    stop_reason: null,
    checker_log: {
      checked_at: new Date().toISOString(),
      total_criteria: checks.length,
      failed_criteria: failedCriteria.length
    }
  }
}];

return [{
  json: {
    ...$json,
    prompt_reference: 'src/prompts/criteria_checker_prompt.md',
    prompt_contract: {
      output: 'criteria_checker_result',
      format: 'json_only'
    }
  }
}];
